import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { ClientInfo } from "src/app/views/Models/Client/ClientInfo";
import * as customValidators from "src/app/core/validators/custom-validators";
import { FormStatus } from "src/app/views/Models/forms/formStatus";
import { HttpErrorResponse } from "@angular/common/http";
import { ClientService } from "src/app/core/services/client.service";

@Component({
  selector: "app-edit-client-before-loan-gen",
  templateUrl: "./edit-client-before-loan-gen.page.html",
  styleUrls: ["./edit-client-before-loan-gen.page.scss"],
})
export class EditClientBeforeLoanGenPage implements OnInit {
  //#region Flags
  showLoader: boolean = false;
  showEditClientComponent: boolean = false;
  //#endregion

  //#region Variables
  existingClientInfo: ClientInfo;
  //#endregion

  //#region Forms
  searchForm: FormGroup = this.FormBuilder.group({
    nationId: [
      null,
      [customValidators.nationalIdValidator({ required: true })],
    ],
  });
  searchFormStatus: FormStatus = {
    visible: true,
    valid: false,
  };
  //#endregion

  constructor(
    private FormBuilder: FormBuilder,
    private alertService: AlertService,
    private clientService: ClientService
  ) {}

  ngOnInit() {}

  async nationIdSearchBtn() {
    this.searchFormStatus.valid = true;
    try {
      this.showLoader = true;
      if (this.searchForm.valid) {
        let nationId: string = this.searchForm.value.nationId;
        let clientById: ClientInfo = await this.clientService.getClientById(
          nationId,
          0,
          1
        );
        // client Exist
        if (clientById) {
          if (
            clientById.client_type_code == "4" ||
            clientById.client_type_code == "2"
          ) {
            return await this.alertService.showAlertError(
              "هذا العميل مسجل في مجموعة / شركات",
              false
            );
          }

          this.existingClientInfo = clientById;
          this.searchFormStatus.visible = false;
          this.showEditClientComponent = true;
        }
        // new client
        else {
          let clientByIdWithAnyBranch =
            await this.clientService.getClientByIdWithAnyBranch(nationId);
          if (clientByIdWithAnyBranch) {
            let alertMessage: string =
              `الرقم القومي مكرر` +
              "<br>" +
              `مع العميل ${clientByIdWithAnyBranch.client_name}` +
              "<br>" +
              `بالفرع ${clientByIdWithAnyBranch.branch_name}` +
              "<br>" +
              `ويحمل كود رقم ${clientByIdWithAnyBranch.client_code}` +
              "<br>" +
              `مع مندوب:  ${clientByIdWithAnyBranch.officer_name}`;
            await this.alertService.showAlertError(alertMessage, false);
            return;
          }
        }
      }
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
